import{_ as a,I as i,g as e,j as n}from"./chunks/framework.CbuNJfvM.js";const u=JSON.parse('{"title":"grammar","description":"","frontmatter":{},"headers":[],"relativePath":"grammar.md","filePath":"grammar.md"}'),t={name:"grammar.md"};function l(p,s,o,r,h,d){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="grammar" tabindex="-1">grammar <a class="header-anchor" href="#grammar" aria-label="Permalink to &quot;grammar&quot;">​</a></h1><p>This page gives the full grammar of ghūl, derived from the compiler&#39;s parser.</p><p>The grammar is written in <a href="https://www.w3.org/TR/xml/#sec-notation" target="_blank" rel="noreferrer">W3C EBNF</a> — the notation used by the XML and XPath specifications:</p><table tabindex="0"><thead><tr><th>Notation</th><th>Meaning</th></tr></thead><tbody><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> ::</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">= ...</span></code></td><td>defines the symbol <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code></td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> B</span></code></td><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code> followed by <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">B</span></code></td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> | </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">B</span></code></td><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code> or <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">B</span></code></td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">?</span></code></td><td>zero or one <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code></td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">*</span></code></td><td>zero or more <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code></td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">+</span></code></td><td>one or more <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code></td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">( ... )</span></code></td><td>grouping</td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;is&quot;</span></code></td><td>a literal terminal</td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">a</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">-</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">z</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code></td><td>a character in the given set</td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[^</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;]</span></code></td><td>any character <em>not</em> in the set</td></tr><tr><td><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> - </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">B</span></code></td><td>an <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">A</span></code> that is not also a <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">B</span></code></td></tr></tbody></table><p><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">CamelCase</span></code> symbols are grammar productions; <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Identifier</span></code>, <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">IntegerLiteral</span></code> and the other symbols defined under <a href="#lexical-grammar">lexical grammar</a> are tokens produced by the tokenizer.</p><p>A few constructs are resolved by the parser using context that a context-free grammar cannot express (operator precedence, and a small number of genuinely context-sensitive forms). These are called out in prose where they arise, and the operator precedence table is given <a href="#operator-precedence">at the end</a>.</p><h2 id="lexical-grammar" tabindex="-1">lexical grammar <a class="header-anchor" href="#lexical-grammar" aria-label="Permalink to &quot;lexical grammar&quot;">​</a></h2><p>The tokenizer turns source text into a stream of tokens. Whitespace — spaces, tabs, carriage returns and newlines — separates tokens but is otherwise insignificant: ghūl is <strong>not</strong> indentation-sensitive. Whitespace and comments are discarded before parsing.</p><h3 id="comments" tabindex="-1">comments <a class="header-anchor" href="#comments" aria-label="Permalink to &quot;comments&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>LineComment  ::= &quot;//&quot; [^#xA]*</span></span>
<span class="line"><span>BlockComment ::= &quot;/*&quot; ( [^*] | &quot;*&quot; [^/] )* &quot;*/&quot;</span></span></code></pre></div><p>Block comments do <strong>not</strong> nest: the first <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">*/</span></code> ends the comment.</p><h3 id="identifiers" tabindex="-1">identifiers <a class="header-anchor" href="#identifiers" aria-label="Permalink to &quot;identifiers&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Identifier        ::= PlainIdentifier | EscapedIdentifier</span></span>
<span class="line"><span>PlainIdentifier   ::= Letter ( Letter | Digit )*</span></span>
<span class="line"><span>EscapedIdentifier ::= &quot;\`&quot; ( Letter | Digit | &quot;_&quot; )+</span></span>
<span class="line"><span>                    | &quot;\`&quot; OperatorChar+</span></span>
<span class="line"><span>Letter            ::= [a-zA-Z_]</span></span>
<span class="line"><span>Digit             ::= [0-9]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>QualifiedIdentifier ::= Identifier ( &quot;.&quot; Identifier )*</span></span></code></pre></div><p>A <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">PlainIdentifier</span></code> may not be one of the <a href="#reserved-words">reserved words</a>. To use a reserved word — or an operator symbol — as an ordinary identifier, prefix it with a backtick: <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">\`</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">field</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">\`+</span></code>.</p><h3 id="reserved-words" tabindex="-1">reserved words <a class="header-anchor" href="#reserved-words" aria-label="Permalink to &quot;reserved words&quot;">​</a></h3><p>The following words are keywords and cannot be used as plain identifiers:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>assert    await     break     case      cast      catch     class</span></span>
<span class="line"><span>continue  default   do        elif      else      enum      esac</span></span>
<span class="line"><span>false     fi        field     finally   for       if        in</span></span>
<span class="line"><span>innate    is        isa       let       mut       namespace new</span></span>
<span class="line"><span>null      od        private   protected ptr       public    rec</span></span>
<span class="line"><span>ref       return    self      si        static    struct    super</span></span>
<span class="line"><span>then      throw     trait     true      try       typeof    union</span></span>
<span class="line"><span>use       when      while     yrt</span></span></code></pre></div><p>A few words are <em>contextual</em> — they look like identifiers to the tokenizer but the parser recognises them in specific positions: <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">optional</span></code> as a type-parameter kind constraint, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">out</span></code> as a type-parameter variance modifier.</p><h3 id="numeric-literals" tabindex="-1">numeric literals <a class="header-anchor" href="#numeric-literals" aria-label="Permalink to &quot;numeric literals&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>IntegerLiteral ::= DecimalInteger | HexInteger</span></span>
<span class="line"><span>DecimalInteger ::= Digit ( Digit | &quot;_&quot; )* IntegerSuffix?</span></span>
<span class="line"><span>HexInteger     ::= ( &quot;0x&quot; | &quot;0X&quot; ) HexDigit ( HexDigit | &quot;_&quot; )* IntegerSuffix?</span></span>
<span class="line"><span>HexDigit       ::= [0-9a-fA-F]</span></span>
<span class="line"><span>IntegerSuffix  ::= ( &quot;s&quot; | &quot;S&quot; | &quot;u&quot; | &quot;U&quot; )? [bBcCsSiIlLwW]?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>FloatLiteral   ::= Digit ( Digit | &quot;_&quot; )* &quot;.&quot; ( Digit | &quot;_&quot; )* Exponent? FloatSuffix?</span></span>
<span class="line"><span>Exponent       ::= ( &quot;e&quot; | &quot;E&quot; ) &quot;-&quot;? ( Digit | &quot;_&quot; )+</span></span>
<span class="line"><span>FloatSuffix    ::= &quot;s&quot; | &quot;S&quot; | &quot;d&quot; | &quot;D&quot;</span></span></code></pre></div><p>Underscores within a number are for readability and are ignored. A float literal must contain a <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span></code>; the type suffix selects <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">single</span></code> (<code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">s</span></code>/<code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">S</span></code>) or <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">double</span></code> (<code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">d</span></code>/<code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">D</span></code>), and an integer suffix selects the integer type and signedness.</p><h3 id="character-and-string-literals" tabindex="-1">character and string literals <a class="header-anchor" href="#character-and-string-literals" aria-label="Permalink to &quot;character and string literals&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>CharLiteral   ::= &quot;&#39;&quot; ( EscapeSequence | [^&#39;] ) &quot;&#39;&quot;</span></span>
<span class="line"><span>StringLiteral ::= &#39;&quot;&#39; StringElement* &#39;&quot;&#39;</span></span>
<span class="line"><span>StringElement ::= EscapeSequence | [^&quot;#xA\\]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>EscapeSequence ::= &quot;\\&quot; ( &quot;t&quot; | &quot;n&quot; | &quot;r&quot; | &quot;\\&quot; | OctalDigit+ | [^#xA] )</span></span>
<span class="line"><span>OctalDigit     ::= [0-7]</span></span></code></pre></div><p>A string literal may not span a newline. Two string literals separated only by whitespace are concatenated into a single literal.</p><p>Inside a string literal, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">{</span></code> begins an <a href="#interpolated-strings">interpolation</a> and <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">}</span></code> ends it; a literal brace is written <code>{{</code> or <code>}}</code>.</p><h3 id="interpolated-strings" tabindex="-1">interpolated strings <a class="header-anchor" href="#interpolated-strings" aria-label="Permalink to &quot;interpolated strings&quot;">​</a></h3><p>A string literal containing <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">{ ... }</span></code> is tokenized as a sequence of fragments rather than a single <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">StringLiteral</span></code>. The parser assembles these as an <a href="#primary-expressions">interpolated string expression</a>:</p><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>InterpolatedString ::= EnterString</span></span>
<span class="line"><span>                       Interpolation</span></span>
<span class="line"><span>                       ( ContinueString Interpolation )*</span></span>
<span class="line"><span>                       ExitString</span></span>
<span class="line"><span>Interpolation      ::= Expression ( &quot;,&quot; Expression )? ( &quot;:&quot; FormatString )?</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">EnterString</span></code>, <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">ContinueString</span></code>, <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">ExitString</span></code> and <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">FormatString</span></code> are the fragments of literal text surrounding and following each interpolated expression. The optional <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">,</span></code> introduces an alignment and the optional <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span></code> a format specifier.</p><h3 id="operators" tabindex="-1">operators <a class="header-anchor" href="#operators" aria-label="Permalink to &quot;operators&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Operator     ::= OperatorChar+</span></span>
<span class="line"><span>OperatorChar ::= [-!$%^&amp;*+=|:@~#\\&lt;&gt;.?/] | UnicodeSymbol</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">UnicodeSymbol</span></code> is any character above U+007E that .NET classifies as a symbol (this admits operators such as <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">×</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">÷</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∩</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∪</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∧</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∨</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">≈</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">≡</span></code>).</p><p>Operators are tokenized greedily — the longest run of operator characters forms one operator — with one exception: a <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span></code> immediately after a leading <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">!</span></code> or <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">?</span></code> ends the operator, so that <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">x</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">!.</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">foo</span></code> and <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">x</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">?.</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">foo</span></code> parse as a member access on an unwrap/has-value, not as the operators <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">!.</span></code> or <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">?.</span></code>.</p><p>A handful of operator spellings are recognised as dedicated tokens rather than general operators: <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span></code>, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span></code>, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">-&gt;</span></code>, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">=&gt;</span></code>, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">?</span></code> and <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">@</span></code>.</p><h2 id="compilation-unit" tabindex="-1">compilation unit <a class="header-anchor" href="#compilation-unit" aria-label="Permalink to &quot;compilation unit&quot;">​</a></h2><p>A source file is a sequence of definitions:</p><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>CompilationUnit ::= Definition*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Definition ::= Namespace</span></span>
<span class="line"><span>             | Use</span></span>
<span class="line"><span>             | Class</span></span>
<span class="line"><span>             | Trait</span></span>
<span class="line"><span>             | Struct</span></span>
<span class="line"><span>             | Union</span></span>
<span class="line"><span>             | Enum</span></span>
<span class="line"><span>             | Member</span></span>
<span class="line"><span>             | PragmaDefinition</span></span></code></pre></div><p>A <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Member</span></code> (function, property or indexer) appearing directly in a compilation unit or namespace is a global function, global variable or global indexer.</p><h2 id="definitions" tabindex="-1">definitions <a class="header-anchor" href="#definitions" aria-label="Permalink to &quot;definitions&quot;">​</a></h2><h3 id="namespace-and-use" tabindex="-1">namespace and use <a class="header-anchor" href="#namespace-and-use" aria-label="Permalink to &quot;namespace and use&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Namespace ::= &quot;namespace&quot; QualifiedIdentifier &quot;is&quot; Definition* &quot;si&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Use ::= &quot;use&quot; QualifiedIdentifier &quot;;&quot;</span></span>
<span class="line"><span>      | &quot;use&quot; Identifier &quot;=&quot; QualifiedIdentifier &quot;;&quot;</span></span></code></pre></div><p>The second form of <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Use</span></code> introduces an alias for a namespace or symbol.</p><h3 id="class-trait-and-struct" tabindex="-1">class, trait and struct <a class="header-anchor" href="#class-trait-and-struct" aria-label="Permalink to &quot;class, trait and struct&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Class  ::= &quot;class&quot;  Identifier TypeParameters? Ancestors? Modifiers</span></span>
<span class="line"><span>           &quot;is&quot; Definition* &quot;si&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Trait  ::= &quot;trait&quot;  Identifier TypeParameters? Ancestors? Modifiers</span></span>
<span class="line"><span>           &quot;is&quot; Definition* &quot;si&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Struct ::= &quot;struct&quot; Identifier TypeParameters? Ancestors? Modifiers</span></span>
<span class="line"><span>           &quot;is&quot; Definition* &quot;si&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>TypeParameters ::= &quot;[&quot; TypeParameter ( &quot;,&quot; TypeParameter )* &quot;]&quot;</span></span>
<span class="line"><span>TypeParameter  ::= Identifier ( &quot;:&quot; TypeParameterConstraints )? Variance?</span></span>
<span class="line"><span>TypeParameterConstraints</span></span>
<span class="line"><span>               ::= TypeExpression KindConstraint? &quot;new&quot;?    /* type bound */</span></span>
<span class="line"><span>                 | KindConstraint &quot;new&quot;?                    /* kind only */</span></span>
<span class="line"><span>                 | &quot;new&quot;                                    /* ctor only */</span></span>
<span class="line"><span>KindConstraint ::= &quot;class&quot; | &quot;struct&quot; | &quot;optional&quot;</span></span>
<span class="line"><span>Variance       ::= &quot;out&quot; | &quot;in&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ancestors ::= &quot;:&quot; TypeList</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Ancestors</span></code> lists the base class and/or implemented traits.</p><p>A type parameter may carry a <em>type bound</em> (which the actual type argument must derive from), a <em>kind constraint</em> (<code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">class</span></code> / <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">struct</span></code> / <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">optional</span></code>), a <em>constructor constraint</em> (<code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">new</span></code>), and on a trait a <em>variance</em> modifier (<code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">out</span></code> for covariant, <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">in</span></code> for contravariant) — in that order. Only a single type bound per parameter is currently supported. Variance is only legal on a trait&#39;s type parameters.</p><h3 id="union" tabindex="-1">union <a class="header-anchor" href="#union" aria-label="Permalink to &quot;union&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Union   ::= &quot;union&quot; Identifier TypeParameters? Modifiers &quot;is&quot; Variant+ &quot;si&quot;</span></span>
<span class="line"><span>Variant ::= Identifier ( &quot;(&quot; VariableList &quot;)&quot; )? &quot;default&quot;? &quot;;&quot;</span></span></code></pre></div><p>Each <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Variant</span></code> optionally carries fields, written as a parenthesised list of <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">name</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Type</span></code> variables. A trailing <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">default</span></code> marks one variant as the union&#39;s <em>default</em> — the one the <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">?</span></code> test and <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">!</span></code> unwrap operators target on a union value.</p><h3 id="enum" tabindex="-1">enum <a class="header-anchor" href="#enum" aria-label="Permalink to &quot;enum&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Enum       ::= &quot;enum&quot; Identifier Modifiers &quot;is&quot;</span></span>
<span class="line"><span>               EnumMember ( &quot;,&quot; EnumMember )* &quot;si&quot;</span></span>
<span class="line"><span>EnumMember ::= Identifier ( &quot;=&quot; Expression )?</span></span></code></pre></div><h3 id="members-functions-properties-and-indexers" tabindex="-1">members: functions, properties and indexers <a class="header-anchor" href="#members-functions-properties-and-indexers" aria-label="Permalink to &quot;members: functions, properties and indexers&quot;">​</a></h3><p>A <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Member</span></code> is a function, a property or an indexer. They share a leading name and modifiers; the parser distinguishes them by what follows the name.</p><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Member ::= Function | Property | Indexer</span></span></code></pre></div><h4 id="function" tabindex="-1">function <a class="header-anchor" href="#function" aria-label="Permalink to &quot;function&quot;">​</a></h4><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Function     ::= FunctionName TypeParameters?</span></span>
<span class="line"><span>                 &quot;(&quot; VariableList? &quot;)&quot; ReturnType? Modifiers ( Body | &quot;;&quot; )</span></span>
<span class="line"><span>FunctionName ::= Identifier | Operator</span></span>
<span class="line"><span>ReturnType   ::= &quot;-&gt;&quot; TypeExpression</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Body ::= &quot;is&quot; StatementList &quot;si&quot;</span></span>
<span class="line"><span>       | &quot;=&gt;&quot; Expression</span></span>
<span class="line"><span>       | &quot;innate&quot; QualifiedIdentifier</span></span></code></pre></div><p>A function may be named by an <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Operator</span></code>, which defines that operator. A function with no body (just <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">;</span></code>) is abstract. A <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">=&gt;</span></code> or <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">innate</span></code> body is terminated by <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">;</span></code>; a block body (<code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">is</span></code> … <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">si</span></code>) is not.</p><h4 id="property" tabindex="-1">property <a class="header-anchor" href="#property" aria-label="Permalink to &quot;property&quot;">​</a></h4><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Property          ::= Identifier ( &quot;:&quot; TypeExpression )? Modifiers</span></span>
<span class="line"><span>                      PropertyAccessors? &quot;;&quot;?</span></span>
<span class="line"><span>PropertyAccessors ::= PropertyGetter ( &quot;,&quot; PropertySetter )?</span></span>
<span class="line"><span>                    | PropertySetter ( &quot;,&quot; PropertyGetter )?</span></span>
<span class="line"><span>PropertyGetter    ::= Body</span></span>
<span class="line"><span>PropertySetter    ::= &quot;=&quot; Identifier Body</span></span></code></pre></div><p>A property with no accessors and the <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">field</span></code> modifier declares a field. A <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">PropertySetter</span></code> names the value parameter after <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=</span></code>. As with functions, a <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">=&gt;</span></code> or <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">innate</span></code> accessor body is terminated by <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">;</span></code> and a block body is not.</p><h4 id="indexer" tabindex="-1">indexer <a class="header-anchor" href="#indexer" aria-label="Permalink to &quot;indexer&quot;">​</a></h4><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Indexer ::= Identifier? &quot;[&quot; Variable &quot;]&quot; ( &quot;:&quot; TypeExpression )? Modifiers</span></span>
<span class="line"><span>            PropertyAccessors? &quot;;&quot;?</span></span></code></pre></div><h3 id="modifiers" tabindex="-1">modifiers <a class="header-anchor" href="#modifiers" aria-label="Permalink to &quot;modifiers&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Modifiers      ::= AccessModifier? StorageClass?</span></span>
<span class="line"><span>AccessModifier ::= &quot;public&quot; | &quot;protected&quot; | &quot;private&quot;</span></span>
<span class="line"><span>StorageClass   ::= &quot;static&quot; | &quot;field&quot;</span></span></code></pre></div><h3 id="pragmas" tabindex="-1">pragmas <a class="header-anchor" href="#pragmas" aria-label="Permalink to &quot;pragmas&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>PragmaDefinition ::= Pragma Definition</span></span>
<span class="line"><span>Pragma           ::= &quot;@&quot; QualifiedIdentifier ( &quot;(&quot; ExpressionList? &quot;)&quot; )?</span></span></code></pre></div><p>A <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Pragma</span></code> annotates the definition (or <a href="#statements">statement</a>) that follows it.</p><h2 id="type-expressions" tabindex="-1">type expressions <a class="header-anchor" href="#type-expressions" aria-label="Permalink to &quot;type expressions&quot;">​</a></h2><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>TypeExpression ::= PrimaryType TypeSuffix*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PrimaryType ::= QualifiedIdentifier</span></span>
<span class="line"><span>              | QualifiedIdentifier &quot;[&quot; TypeList &quot;]&quot;   /* generic type */</span></span>
<span class="line"><span>              | QualifiedIdentifier &quot;[&quot; &quot;]&quot;            /* array type */</span></span>
<span class="line"><span>              | Identifier &quot;:&quot; TypeExpression          /* named tuple element */</span></span>
<span class="line"><span>              | &quot;(&quot; TypeList &quot;)&quot;                       /* tuple, or grouping */</span></span>
<span class="line"><span>              | &quot;(&quot; TypeList? &quot;)&quot; &quot;-&gt;&quot; TypeExpression  /* function type */</span></span>
<span class="line"><span></span></span>
<span class="line"><span>TypeSuffix ::= &quot;[]&quot;                  /* array */</span></span>
<span class="line"><span>             | &quot;ref&quot;                 /* by-reference */</span></span>
<span class="line"><span>             | &quot;ptr&quot;                 /* pointer */</span></span>
<span class="line"><span>             | &quot;?&quot;                   /* nullable */</span></span>
<span class="line"><span>             | &quot;-&gt;&quot; TypeExpression   /* function type */</span></span>
<span class="line"><span>             | &quot;.&quot; Identifier        /* member type */</span></span>
<span class="line"><span></span></span>
<span class="line"><span>TypeList ::= TypeExpression ( &quot;,&quot; TypeExpression )*</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">( </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> )</span></code> is just <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span></code> in parentheses — parentheses group, e.g. to disambiguate <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">a</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -&gt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> b</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">) </span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">-&gt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> c</span></code> from <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">a</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -&gt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> b</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> -&gt;</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> c</span></code>. A parenthesised list of two or more types is a tuple type. Empty parentheses are meaningful only as <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">( ) </span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">-&gt;</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> T</span></code>, a function type taking no arguments. A <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">name</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Type</span></code> element gives a tuple element a name.</p><h2 id="variables" tabindex="-1">variables <a class="header-anchor" href="#variables" aria-label="Permalink to &quot;variables&quot;">​</a></h2><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Variable     ::= VariableLeft ( &quot;:&quot; TypeExpression )? &quot;mut&quot;? ( &quot;=&quot; Expression )?</span></span>
<span class="line"><span>VariableLeft ::= Identifier</span></span>
<span class="line"><span>               | &quot;(&quot; VariableLeft ( &quot;,&quot; VariableLeft )* &quot;)&quot;</span></span>
<span class="line"><span>VariableList ::= Variable ( &quot;,&quot; Variable )*</span></span></code></pre></div><p>The parenthesised form of <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">VariableLeft</span></code> destructures a tuple. A bare <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">let</span></code> local variable is immutable unless followed by <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">mut</span></code>.</p><h2 id="statements" tabindex="-1">statements <a class="header-anchor" href="#statements" aria-label="Permalink to &quot;statements&quot;">​</a></h2><p>A statement list is a sequence of statements. A <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">;</span></code> separates statements; it is required after a statement whose syntax would otherwise run on into the next, and optional elsewhere.</p><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>StatementList ::= ( Statement &quot;;&quot;? )*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Statement ::= Let</span></span>
<span class="line"><span>            | Return</span></span>
<span class="line"><span>            | Throw</span></span>
<span class="line"><span>            | Assert</span></span>
<span class="line"><span>            | Yield</span></span>
<span class="line"><span>            | If</span></span>
<span class="line"><span>            | Case</span></span>
<span class="line"><span>            | Try</span></span>
<span class="line"><span>            | Loop</span></span>
<span class="line"><span>            | For</span></span>
<span class="line"><span>            | Break</span></span>
<span class="line"><span>            | Continue</span></span>
<span class="line"><span>            | PragmaStatement</span></span>
<span class="line"><span>            | Labelled</span></span>
<span class="line"><span>            | Assignment</span></span>
<span class="line"><span>            | ExpressionStatement</span></span></code></pre></div><h3 id="local-variable-definitions-return-throw-assert-yield" tabindex="-1">local variable definitions, return, throw, assert, yield <a class="header-anchor" href="#local-variable-definitions-return-throw-assert-yield" aria-label="Permalink to &quot;local variable definitions, return, throw, assert, yield&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Let    ::= &quot;let&quot; &quot;use&quot;? VariableList ( &quot;in&quot; Expression )?</span></span>
<span class="line"><span>Return ::= &quot;return&quot; Expression?</span></span>
<span class="line"><span>Throw  ::= &quot;throw&quot; Expression?</span></span>
<span class="line"><span>Assert ::= &quot;assert&quot; Expression ( &quot;else&quot; Expression )?</span></span>
<span class="line"><span>Yield  ::= &quot;yield&quot; Expression</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">let</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> use</span></code> defines a local variable holding a disposable, whose <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">dispose</span></code> is called when the variable goes out of scope.</p><p>The <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">let</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> … </span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">in</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> …</span></code> form is a <a href="#primary-expressions">let-in expression</a> used as a statement.</p><p><code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">yield</span></code> is permitted only inside a <a href="/control-flow.html#generators">generator function</a> — one whose return type is <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Collections</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Iterable</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> or <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Collections</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Iterator</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code>.</p><h3 id="if" tabindex="-1">if <a class="header-anchor" href="#if" aria-label="Permalink to &quot;if&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>If          ::= &quot;if&quot;   IfCondition &quot;then&quot; StatementList</span></span>
<span class="line"><span>                ( &quot;elif&quot; IfCondition &quot;then&quot; StatementList )*</span></span>
<span class="line"><span>                ( &quot;else&quot;             StatementList )?</span></span>
<span class="line"><span>                &quot;fi&quot;</span></span>
<span class="line"><span>IfCondition ::= Expression</span></span>
<span class="line"><span>              | &quot;let&quot; Variable        /* if-let local variable */</span></span></code></pre></div><p>The <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">if</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> let</span></code> form defines a local variable whose initializer must be present; a type ascription on it (<code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">if</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> let</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;"> c</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> = </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">e</span></code>) tests that the value is a <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span></code>.</p><h3 id="case" tabindex="-1">case <a class="header-anchor" href="#case" aria-label="Permalink to &quot;case&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Case ::= &quot;case&quot; Expression</span></span>
<span class="line"><span>         ( &quot;when&quot; ExpressionList &quot;:&quot; StatementList )*</span></span>
<span class="line"><span>         ( &quot;default&quot; StatementList )?</span></span>
<span class="line"><span>         &quot;esac&quot;</span></span></code></pre></div><h3 id="try" tabindex="-1">try <a class="header-anchor" href="#try" aria-label="Permalink to &quot;try&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Try ::= &quot;try&quot; StatementList</span></span>
<span class="line"><span>        ( &quot;catch&quot; Variable StatementList )*</span></span>
<span class="line"><span>        ( &quot;finally&quot; StatementList )?</span></span>
<span class="line"><span>        &quot;yrt&quot;</span></span></code></pre></div><h3 id="loops" tabindex="-1">loops <a class="header-anchor" href="#loops" aria-label="Permalink to &quot;loops&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Loop ::= ( &quot;while&quot; Expression )? &quot;do&quot; StatementList &quot;od&quot;</span></span>
<span class="line"><span>For  ::= &quot;for&quot; Variable &quot;in&quot; Expression &quot;do&quot; StatementList &quot;od&quot;</span></span></code></pre></div><p>A <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">do</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> … </span><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">od</span></code> with no <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">while</span></code> is an unconditional loop.</p><h3 id="break-continue-and-labels" tabindex="-1">break, continue and labels <a class="header-anchor" href="#break-continue-and-labels" aria-label="Permalink to &quot;break, continue and labels&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Break    ::= &quot;break&quot; Identifier?</span></span>
<span class="line"><span>Continue ::= &quot;continue&quot; Identifier?</span></span>
<span class="line"><span>Labelled ::= Identifier &quot;:&quot; Statement</span></span></code></pre></div><p>A <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Labelled</span></code> statement may be targeted by <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">break</span></code> or <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">continue</span></code> with the matching label.</p><h3 id="assignment-and-expression-statements" tabindex="-1">assignment and expression statements <a class="header-anchor" href="#assignment-and-expression-statements" aria-label="Permalink to &quot;assignment and expression statements&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Assignment          ::= Expression &quot;=&quot; Expression</span></span>
<span class="line"><span>ExpressionStatement ::= Expression</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PragmaStatement     ::= Pragma Statement</span></span></code></pre></div><h2 id="expressions" tabindex="-1">expressions <a class="header-anchor" href="#expressions" aria-label="Permalink to &quot;expressions&quot;">​</a></h2><p>An expression is a sequence of operands joined by binary operators. The parser resolves operator nesting by <a href="#operator-precedence">precedence</a>; the grammar below gives the flat structure.</p><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>Expression ::= UnaryExpression ( Operator UnaryExpression )*</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">||</span></code> is the <em>yield infix</em> used to produce a value from a generator step; it has the lowest precedence and does not chain.</p><h3 id="unary-expressions" tabindex="-1">unary expressions <a class="header-anchor" href="#unary-expressions" aria-label="Permalink to &quot;unary expressions&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>UnaryExpression ::= Operator UnaryExpression      /* prefix operator */</span></span>
<span class="line"><span>                  | &quot;await&quot;  UnaryExpression      /* await expression */</span></span>
<span class="line"><span>                  | PostfixExpression</span></span></code></pre></div><p>An <code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">await</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> E</span></code> expression is permitted only inside an <a href="/control-flow.html#asynchronous-code">asynchronous function</a> — one whose return type is <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Tasks</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">TASK</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]</span></code> (or <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Tasks</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">TASK</span></code>) — and evaluates to the result of the awaited task once it completes. Used as the right-hand side of <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">let</span></code>, as a bare statement (<code class="ghul-inline"><span style="--shiki-light:#AF00DB;--shiki-dark:#C586C0;">await</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> E</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">;</span></code>), or in any operand position.</p><h3 id="postfix-expressions" tabindex="-1">postfix expressions <a class="header-anchor" href="#postfix-expressions" aria-label="Permalink to &quot;postfix expressions&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>PostfixExpression ::= PrimaryExpression PostfixSuffix*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PostfixSuffix ::= &quot;(&quot; ExpressionList? &quot;)&quot;     /* call */</span></span>
<span class="line"><span>                | &quot;[&quot; ExpressionList &quot;]&quot;      /* index expression, or generic application */</span></span>
<span class="line"><span>                | &quot;\`[&quot; TypeList &quot;]&quot;           /* explicit generic application */</span></span>
<span class="line"><span>                | &quot;.&quot; Identifier              /* member access */</span></span>
<span class="line"><span>                | &quot;?&quot;                         /* has-value test */</span></span>
<span class="line"><span>                | &quot;!&quot;                         /* unwrap */</span></span>
<span class="line"><span>                | &quot;ref&quot;                       /* by-reference */</span></span>
<span class="line"><span>                | &quot;|&quot;                         /* pipe */</span></span></code></pre></div><p>A <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[ ... ]</span></code> suffix is either an index expression — an access through an <a href="#indexer">indexer</a> — or a generic type application, depending on whether its contents resolve as expressions or as types; <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">\`[ ... ]</span></code> forces the generic-application reading.</p><h3 id="function-literals" tabindex="-1">function literals <a class="header-anchor" href="#function-literals" aria-label="Permalink to &quot;function literals&quot;">​</a></h3><p>A primary expression — or a parenthesised argument list — followed by <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">-&gt;</span></code>, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">=&gt;</span></code>, <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">is</span></code> or <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">rec</span></code> is a function literal:</p><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>FunctionLiteral   ::= FunctionArguments ( &quot;-&gt;&quot; TypeExpression )? &quot;rec&quot;? Body</span></span>
<span class="line"><span>FunctionArguments ::= &quot;(&quot; VariableList? &quot;)&quot;</span></span>
<span class="line"><span>                    | Identifier</span></span></code></pre></div><p><code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">rec</span></code> marks the literal as recursive, so it may refer to itself.</p><h3 id="primary-expressions" tabindex="-1">primary expressions <a class="header-anchor" href="#primary-expressions" aria-label="Permalink to &quot;primary expressions&quot;">​</a></h3><div class="language-ebnf vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ebnf</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span>PrimaryExpression ::= Identifier</span></span>
<span class="line"><span>                    | Literal</span></span>
<span class="line"><span>                    | &quot;(&quot; ExpressionList? &quot;)&quot;                /* tuple or grouping */</span></span>
<span class="line"><span>                    | &quot;[&quot; ExpressionList &quot;]&quot; ( &quot;:&quot; TypeExpression )?  /* list literal */</span></span>
<span class="line"><span>                    | &quot;cast&quot; TypeExpression &quot;(&quot; Expression &quot;)&quot;</span></span>
<span class="line"><span>                    | &quot;isa&quot; TypeExpression &quot;(&quot; Expression &quot;)&quot;</span></span>
<span class="line"><span>                    | &quot;typeof&quot; TypeExpression</span></span>
<span class="line"><span>                    | &quot;default&quot; ( &quot;[&quot; TypeExpression &quot;]&quot; )?</span></span>
<span class="line"><span>                    | &quot;self&quot;</span></span>
<span class="line"><span>                    | &quot;super&quot;</span></span>
<span class="line"><span>                    | &quot;rec&quot;</span></span>
<span class="line"><span>                    | If                                     /* if-expression */</span></span>
<span class="line"><span>                    | &quot;let&quot; &quot;use&quot;? VariableList &quot;in&quot; Expression   /* let-in */</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Literal ::= IntegerLiteral</span></span>
<span class="line"><span>          | FloatLiteral</span></span>
<span class="line"><span>          | StringLiteral</span></span>
<span class="line"><span>          | CharLiteral</span></span>
<span class="line"><span>          | InterpolatedString</span></span>
<span class="line"><span>          | &quot;true&quot; | &quot;false&quot;</span></span>
<span class="line"><span>          | &quot;null&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ExpressionList ::= Expression ( &quot;,&quot; Expression )*</span></span></code></pre></div><p>A list literal <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[ </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">a</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">b</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, ... ]</span></code> builds a <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">List</span></code>; it requires at least one element (use <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">LIST</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">[</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">T</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">]()</span></code> for an empty list).</p><p>Within an <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">ExpressionList</span></code> that forms call arguments or a tuple, an element of the form <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Identifier</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> &quot;:&quot;</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> TypeExpression</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">? ( </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;=&quot;</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> Expression</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> )?</span></code> is an inline local variable definition rather than a plain identifier — this is the only place that form is accepted.</p><h2 id="operator-precedence" tabindex="-1">operator precedence <a class="header-anchor" href="#operator-precedence" aria-label="Permalink to &quot;operator precedence&quot;">​</a></h2><p>ghūl has no fixed list of binary operators: any <a href="#operators">operator token</a> may be used infix. Precedence is assigned by a table of built-in operators plus a first-character heuristic for everything else, so the grammar&#39;s flat <code class="ghul-inline"><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Expression</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;"> ::</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">= </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">UnaryExpression</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> ( </span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;">Operator</span><span style="--shiki-light:#267F99;--shiki-dark:#4EC9B0;"> UnaryExpression</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;"> )*</span></code> is disambiguated by the following levels, <strong>tightest first</strong>:</p><table tabindex="0"><thead><tr><th>Precedence</th><th>Operators</th></tr></thead><tbody><tr><td><em>(prefix unary, member access, call, index — tightest)</em></td><td></td></tr><tr><td>user‑8</td><td><em>(user-defined)</em></td></tr><tr><td>multiplication</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">*</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">×</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">✕</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">/</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">%</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">÷</span></code></td></tr><tr><td>user‑7</td><td><em>(user-defined)</em></td></tr><tr><td>addition</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">+</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">-</span></code></td></tr><tr><td>user‑6</td><td><em>(user-defined)</em></td></tr><tr><td>bitwise</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&amp;</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">|</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">¦</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">^</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∩</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∪</span></code></td></tr><tr><td>user‑5</td><td><em>(user-defined — default)</em></td></tr><tr><td>shift</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;&lt;</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;&gt;</span></code></td></tr><tr><td>user‑4</td><td><em>(user-defined)</em></td></tr><tr><td>range</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">..</span></code> <code class="ghul-inline"><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">::</span></code></td></tr><tr><td>user‑3</td><td><em>(user-defined)</em></td></tr><tr><td>relational</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">==</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">!=</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">=~</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">!~</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;=</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;=</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">≈</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">≡</span></code></td></tr><tr><td>user‑2</td><td><em>(user-defined)</em></td></tr><tr><td>boolean</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">/\\</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">\\/</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∧</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">∨</span></code></td></tr><tr><td>user‑1</td><td><em>(user-defined)</em></td></tr><tr><td>yield infix</td><td><code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">||</span></code></td></tr></tbody></table><p>All binary operators are left-associative. Prefix unary operators, member access, calls and indexing bind more tightly than any binary operator.</p><p>A user-defined operator — any operator not in the table above — is assigned a precedence from its <strong>first character</strong>, modelled on OCaml and F#: operators starting with <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">*</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">/</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">%</span></code> bind as multiplication, <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">+</span></code> <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">-</span></code> as addition, and so on; an operator with no recognised first character defaults to user‑5. The <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">@</span><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">precedence</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">(</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;op&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">, </span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;">&quot;level&quot;</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">)</span></code> pragma overrides the precedence of a named operator. Both arguments must be string literals — a numeric <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">level</span></code> is not accepted — and <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">level</span></code> names a precedence level: <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">user</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">-</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">1</span></code> … <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">user</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">-</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">8</span></code>, or one of the built-in level names <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">boolean</span></code>, <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">relational</span></code>, <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">range</span></code>, <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">shift</span></code>, <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">bitwise</span></code>, <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">addition</span></code> and <code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">multiplication</span></code>.</p>`,119)])])}const k=a(t,[["render",l]]);export{u as __pageData,k as default};
